package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetHeaderWhenHeaderIsNull() throws Exception {
        // Create CSVFormat instance with header = null using reflection
        CSVFormat format = CSVFormat.DEFAULT;
        // Use reflection to create a CSVFormat instance with header=null
        CSVFormat formatWithNullHeader = createCSVFormatWithHeader(null);
        assertNull(formatWithNullHeader.getHeader());
    }

    @Test
    void testGetHeaderWhenHeaderIsNotNull() throws Exception {
        String[] header = new String[] {"col1", "col2", "col3"};
        CSVFormat formatWithHeader = createCSVFormatWithHeader(header);
        String[] returnedHeader = formatWithHeader.getHeader();
        assertNotNull(returnedHeader);
        assertArrayEquals(header, returnedHeader);
        // Ensure clone: modifying returned array does not affect original
        returnedHeader[0] = "modified";
        String[] returnedHeader2 = formatWithHeader.getHeader();
        assertEquals("col1", returnedHeader2[0]);
    }

    private CSVFormat createCSVFormatWithHeader(String[] header) throws Exception {
        // Use reflection to invoke private constructor of CSVFormat with header array
        // Constructor signature:
        // CSVFormat(char delimiter, Character quoteChar, QuoteMode quoteMode,
        // Character commentStart, Character escape, boolean ignoreSurroundingSpaces,
        // boolean ignoreEmptyLines, String recordSeparator, String nullString,
        // Object[] headerComments, String[] header, boolean skipHeaderRecord,
        // boolean allowMissingColumnNames, boolean ignoreHeaderCase, boolean trim,
        // boolean trailingDelimiter)
        java.lang.reflect.Constructor<CSVFormat> constructor =
                CSVFormat.class.getDeclaredConstructor(
                        char.class,
                        Character.class,
                        Class.forName("org.apache.commons.csv.QuoteMode"),
                        Character.class,
                        Character.class,
                        boolean.class,
                        boolean.class,
                        String.class,
                        String.class,
                        Object[].class,
                        String[].class,
                        boolean.class,
                        boolean.class,
                        boolean.class,
                        boolean.class,
                        boolean.class);
        constructor.setAccessible(true);
        // Pass null for QuoteMode since it's an enum, use null safely
        return constructor.newInstance(
                ',',
                '"',
                null,
                null,
                null,
                false,
                true,
                "\r\n",
                null,
                null,
                header,
                false,
                false,
                false,
                false,
                false);
    }
}
